def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 8:
            for a in range(8, 3, -1):
                term1 = ((ratio - a) ** 6) / (a * 1.5 + 1)
                for b in range(1, a+5):
                    coef = np.sin(ratio * b / (a + 2)) * ((ratio - a) ** 2)
                    priority += term1 * coef * np.tanh(b * 0.8)
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.7:
                priority += np.log1p(item * bin_cap) * 7.5
        elif 5 < ratio <= 8:
            s = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 1)
                    s += np.tanh(val) * 1.8
            priority = s + np.log(ratio) * 13 - np.tanh(ratio - 5.5) * 3
            if (i * int(item*1.7)) % 5 == 0:
                priority *= 1.35
        elif 3 <= ratio <= 5:
            acc = 0
            for r in range(1, 20):
                acc += ((ratio - 3) ** r) / (r**1.5 + 1) * np.sin(r * ratio * 1.2)
            priority = (acc * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(5.5 - ratio) * 2
            if bin_cap > item * 3:
                priority -= np.exp(-0.5 * ratio) * 2.5
        elif 1 < ratio < 3:
            s1 = 0
            for n in range(1, 12):
                s1 += ((3 - ratio) ** n) / (n ** 3 + 0.2) * np.cos(n * ratio * 1.7)
            s2 = 0
            for m in range(1, 7):
                s2 += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
            penalty = 0
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 3.5
            else:
                penalty = np.cos(25 * ratio) * 1.9
            priority = s1 + s2 + penalty + np.exp(-2 / (ratio + 0.1))
        elif 0.5 <= ratio <= 1:
            s = 0
            for x in range(1, 20):
                s += ((1 - ratio) ** x) / (x * 5 + 1) * np.sin(x * ratio * 2)
            priority = s
            if (i + int(item * 2)) % 3 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.5)
            for y in range(1, 7):
                priority += ((1 - ratio) ** y) * np.cos(y * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.8) % 6 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.35:
                priority += np.log1p(item * bin_cap) * 5.2
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 8) * np.sin(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.2 - ratio) ** t) / (t * 7) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.8
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 1.0)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if (i * int(item)) % 7 == 0:
            priority += np.log1p(bin_cap + item) * 2.5
        else:
            priority -= np.sqrt(bin_cap + 1)
        priorities[i] = priority
    return priorities
